///|
test "grader audits originals before replacement" {
  let values = [1, 2, 3, 4]
  let original_sum = replace_and_audit(values, 1, 3, 9)
  assert_eq(original_sum, 5)
  assert_eq(values, [1, 9, 9, 4])
}

///|
test "grader handles whole and empty windows" {
  let whole = [4, 5]
  assert_eq(replace_and_audit(whole, 0, 2, 0), 9)
  assert_eq(whole, [0, 0])
  let unchanged = [7, 8]
  assert_eq(replace_and_audit(unchanged, 1, 1, 3), 0)
  assert_eq(unchanged, [7, 8])
}
